import React, { useState, useRef, useEffect } from 'react';
import { Filter, ChevronDown, Search, Check } from './Icons';

type FilterOption = {
  id: string;
  label: string;
  checked: boolean;
};

interface DropdownProps {
  label: string;
  options: FilterOption[];
  hasSearch?: boolean;
  isActive?: boolean;
}

const FilterDropdown: React.FC<DropdownProps> = ({ label, options: initialOptions, hasSearch = true, isActive = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [options, setOptions] = useState(initialOptions);
  const [search, setSearch] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleOption = (id: string) => {
    setOptions(prev => prev.map(opt => 
      opt.id === id ? { ...opt, checked: !opt.checked } : opt
    ));
  };

  const filteredOptions = options.filter(opt => 
    opt.label.toLowerCase().includes(search.toLowerCase())
  );

  const selectedCount = options.filter(o => o.checked).length;
  const isAllSelected = selectedCount === options.length;
  const labelText = isActive && selectedCount > 0 && selectedCount < options.length 
    ? `${label.split(':')[0]}: ${options.find(o => o.checked)?.label}${selectedCount > 1 ? ` +${selectedCount - 1}` : ''}`
    : label;

  return (
    <div className="relative" ref={dropdownRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-colors border ${
          isActive || isOpen 
            ? 'bg-blue-50 text-blue-700 border-blue-200' 
            : 'bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100'
        }`}
      >
        <span className="truncate max-w-[150px]">{labelText}</span>
        <ChevronDown size={14} className={`transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute top-full left-0 mt-2 w-64 bg-white rounded-lg shadow-xl border border-gray-100 z-50 overflow-hidden">
           {/* Header / Search */}
           <div className="p-2 border-b border-gray-100">
             {hasSearch ? (
                <div className="relative">
                  <Search size={14} className="absolute left-3 top-2.5 text-gray-400" />
                  <input 
                    type="text" 
                    placeholder="Type to search" 
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border-none rounded-md text-sm focus:ring-1 focus:ring-blue-500 outline-none"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>
             ) : (
               <div className="px-2 py-1 font-semibold text-gray-700 text-sm">{label}</div>
             )}
           </div>

           {/* Options List */}
           <div className="max-h-60 overflow-y-auto p-1">
             {filteredOptions.map((opt) => (
               <label key={opt.id} className="flex items-center gap-3 px-3 py-2 hover:bg-gray-50 rounded cursor-pointer group">
                 <div className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${opt.checked ? 'bg-gray-600 border-gray-600' : 'border-gray-300 group-hover:border-gray-400'}`}>
                    {opt.checked && <Check size={10} className="text-white" />}
                 </div>
                 <span className="text-sm text-gray-700">{opt.label}</span>
               </label>
             ))}
           </div>
        </div>
      )}
    </div>
  );
};

