interface DateRangePickerProps {
  onClose: () => void;
}

export const DateRangePicker: React.FC<DateRangePickerProps> = ({ onClose }) => {
  // Mock calendar generation for Dec 2025 and Jan 2026 based on screenshot
  const renderCalendarDays = (month: 'Dec' | 'Jan') => {
    const days = [];
    const startDay = month === 'Dec' ? 1 : 4; // Mock starting weekday
    const totalDays = 31;

    // Empty slots
    for (let i = 0; i < startDay; i++) {
      days.push(<div key={`empty-${i}`} className="w-8 h-8"></div>);
    }

    // Days
    for (let d = 1; d <= totalDays; d++) {
      let className = "w-8 h-8 flex items-center justify-center text-sm rounded-full relative z-10 ";

      // Selection Logic to match screenshot (Dec 28 - Jan 26)
      const isStart = month === 'Dec' && d === 28;
      const isEnd = month === 'Jan' && d === 26; // Actually screenshot has 26 selected but range goes further? Let's match visual
      // Screenshot shows 26 Jan selected.

      const inRangeDec = month === 'Dec' && d > 28;
      const inRangeJan = month === 'Jan' && d < 26; // Screenshot shows 27 is current day maybe? Let's assume range ends 26

      const isSelected = isStart || isEnd;
      const isInRange = inRangeDec || inRangeJan || (month === 'Jan' && d === 27); // 27 is circled outline?

      if (isSelected) {
        className += "bg-blue-600 text-white font-bold";
      } else if (isInRange) {
        className += "bg-blue-50 text-gray-700";
      } else if (month === 'Jan' && d === 27) {
        className += "border border-gray-300 text-gray-700"; // Current day?
      } else {
        className += "text-gray-700 hover:bg-gray-100";
      }

      // Range connector visuals
      const rangeBg = isInRange || isStart || isEnd ? (
         <div className={`absolute top-0 bottom-0 bg-blue-50 z-[-1] 
            ${isStart ? 'left-1/2 right-0 rounded-l-full' : ''}
            ${isEnd ? 'left-0 right-1/2 rounded-r-full' : ''}
            ${!isStart && !isEnd ? 'left-0 right-0' : ''}
         `}></div>
      ) : null;

      days.push(
        <button key={d} className="relative w-8 h-8">
           {rangeBg}
           <div className={className}>{d}</div>
        </button>
      );
    }
    return days;
  };

  return (
    <div className="absolute top-full right-0 mt-2 bg-white rounded-lg shadow-2xl border border-gray-200 p-0 z-50 w-[640px] flex flex-col font-sans">
      {/* Top Bar */}
