         <div className="flex items-center gap-2">
            <input type="checkbox" className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500 bg-transparent" />
            <span className="text-sm font-medium">Include today</span>
         </div>
         <div className="relative">
             <button className="flex items-center gap-2 px-3 py-1.5 bg-[#172554] rounded text-sm font-medium border border-[#3b82f6]/30">
                 Last 30 days
                 <ChevronDown size={14} />
             </button>
         </div>
      </div>

      {/* Calendars Container */}
      <div className="flex p-6 gap-8">
          {/* Left Calendar (Dec 2025) */}
          <div className="flex-1">
             <div className="flex flex-col items-center mb-4">
                 <span className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-1">Start Date</span>
                 <div className="flex items-center justify-between w-full">
                     <span className="text-lg font-bold text-gray-800">DEC 2025</span>
                     <div className="flex gap-2">
                        <button className="p-1 hover:bg-gray-100 rounded"><ChevronLeft size={16}/></button>
                        <button className="p-1 hover:bg-gray-100 rounded"><ChevronRight size={16}/></button>
                     </div>
                 </div>
             </div>

             <div className="grid grid-cols-7 gap-y-2 text-center">
                 {['S','M','T','W','T','F','S'].map(d => <div key={d} className="text-xs font-medium text-gray-400 w-8">{d}</div>)}
                 {renderCalendarDays('Dec')}
             </div>
          </div>

          {/* Right Calendar (Jan 2026) */}
          <div className="flex-1">
            <div className="flex flex-col items-center mb-4">
                 <span className="text-xs text-gray-500 font-bold uppercase tracking-wider mb-1">End Date</span>
