import React, { useState, useRef, useEffect } from 'react';
import { Filter, ChevronDown, Search, Check, Minus } from './Icons';

type FilterOption = {
  id: string;
  label: string;
  checked: boolean;
};

interface DropdownProps {
  label: string;
  options: FilterOption[];
  hasSearch?: boolean;
  isActive?: boolean;
}

const FilterDropdown: React.FC<DropdownProps> = ({ label, options: initialOptions, hasSearch = true, isActive = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [options, setOptions] = useState(initialOptions);
  const [search, setSearch] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleOption = (id: string) => {
    setOptions(prev => prev.map(opt => 
      opt.id === id ? { ...opt, checked: !opt.checked } : opt
    ));
  };

  const filteredOptions = options.filter(opt => 
    opt.label.toLowerCase().includes(search.toLowerCase())
  );

  const selectedCount = options.filter(o => o.checked).length;
  // const isAllSelected = selectedCount === options.length;

  // Logic to show count in label similar to "Conversions (1)" in screenshot
  const headerLabel = selectedCount > 0 && selectedCount < options.length 
    ? `${label.split(':')[0]} (${selectedCount})` 
    : label;

  return (
    <div className="relative font-sans" ref={dropdownRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-colors border shadow-sm ${
          isActive
            ? 'bg-gray-100 text-gray-800 border-gray-200' 
            : 'bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100'
        }`}
      >
        <span className="truncate max-w-[150px]">{headerLabel}</span>
        <ChevronDown size={14} className={`text-gray-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute top-full left-0 mt-2 w-72 bg-white rounded-lg shadow-xl border border-gray-100 z-50 overflow-hidden">
           {/* Header / Search */}
           <div className="p-3 border-b border-gray-100">
             {/* Mimic the "Conversions (1)" header in dropdown */}
             <div className="flex items-center justify-between mb-2">
                 <div className="flex items-center gap-2">
                    <div className="bg-gray-200 p-0.5 rounded"><Minus size={12} className="text-gray-600" /></div>
                    <span className="font-bold text-gray-800 text-sm">{label.split(':')[0]} ({selectedCount})</span>
                 </div>
             </div>

             {hasSearch && (
                <div className="relative">
                  <Search size={14} className="absolute left-3 top-2.5 text-gray-400" />
                  <input 
                    type="text" 
                    placeholder="Type to search" 
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border-none rounded-md text-sm text-gray-700 focus:ring-1 focus:ring-blue-500 outline-none"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>
             )}
           </div>

           {/* Options List */}
           <div className="max-h-80 overflow-y-auto p-1 custom-scrollbar">
             {filteredOptions.map((opt) => (
               <label key={opt.id} className="flex items-center gap-3 px-3 py-2.5 hover:bg-gray-50 rounded cursor-pointer group select-none transition-colors">
                 <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${opt.checked ? 'bg-gray-500 border-gray-500' : 'border-gray-300 group-hover:border-gray-400 bg-white'}`}>
                    {opt.checked && <Check size={14} className="text-white" />}
                 </div>
                 <span className="text-sm text-gray-700">{opt.label}</span>
               </label>
             ))}
           </div>
        </div>
      )}
    </div>
  );
};

