// Helper for dates
const getDate = (daysAgo: number) => {
  const date = new Date('2026-01-25'); // Anchored to screenshot date somewhat
  date.setDate(date.getDate() - daysAgo);
  const month = date.toLocaleString('default', { month: 'short' });
  const day = date.getDate();
  const year = date.getFullYear();
  return `${month} ${day}, ${year}`;
};

const generateAdsTimeline = () => {
  const data = [];
  for (let i = 29; i >= 0; i--) {
    // Generate a wavy line similar to screenshot
    const base = 70;
    const wave = Math.sin(i / 2) * 30;
    const noise = Math.random() * 20 - 10;
    const conversions = Math.max(40, Math.floor(base + wave + noise));
    const previous = Math.max(40, Math.floor(base + Math.cos(i / 2) * 20 + noise));

    data.push({
      date: getDate(i),
      conversions: conversions,
      previousConversions: previous
    });
  }
  return data;
};

