const MetricsDropdown = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [metrics, setMetrics] = useState([
    { label: 'Conversions', checked: true },
    { label: 'Impressions', checked: false },
    { label: 'Frequency', checked: false },
    { label: 'Link Clicks', checked: false },
