  return (
    <div className="relative" ref={dropdownRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`p-1.5 rounded-md hover:bg-gray-100 text-gray-400 hover:text-blue-600 transition-colors ${isOpen ? 'bg-blue-50 text-blue-600' : ''}`}
