            const metricConfig = AVAILABLE_METRICS.find(m => m.key === key) || { label: key, color: '#9ca3af', yAxisId: 'left' };
            const isPrevious = key === 'previousConversions';

            // Special handling for previous conversions comparison line style
            if (isPrevious) {
               return (
                <Line 
