  { key: 'conversionRate', label: 'Conversion Rate %', color: '#6366f1', yAxisId: 'right' },
  { key: 'costPerConversion', label: 'Cost per Conversion', color: '#ef4444', yAxisId: 'right' },
  { key: 'frequency', label: 'Frequency', color: '#14b8a6', yAxisId: 'right' },
